        if self.is_playing() {
            attrs.set(HtmlAttr::Aria(AriaAttr::Live), "off");
        } else {
            attrs.set(HtmlAttr::Aria(AriaAttr::Live), "polite");
        }
        if self.ctx.disabled {
            attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true");
            attrs.set_bool(HtmlAttr::Data("ars-disabled"), true);
        }
